import { useState } from 'react';

export default function App() {
  const [todos, setTodos] = useState([]);
  const [input, setInput] = useState('');

  const addTodo = (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    setTodos([...todos, { id: Date.now(), text: input, done: false }]);
    setInput('');
  };

  const toggle = (id) => {
    setTodos(todos.map(t => t.id === id ? { ...t, done: !t.done } : t));
  };

  return (
    <div className="p-8 max-w-md mx-auto">
      <h1 className="text-2xl font-bold mb-4">My Tasks</h1>
      <form onSubmit={addTodo} className="flex gap-2 mb-6">
        <input 
          value={input} 
          onChange={e => setInput(e.target.value)}
          className="flex-1 bg-gray-800 border border-gray-700 px-3 py-2 rounded"
          placeholder="What needs to be done?"
        />
        <button className="bg-violet-600 px-4 py-2 rounded font-medium">Add</button>
      </form>
      <ul className="space-y-2">
        {todos.map(todo => (
          <li 
            key={todo.id} 
            onClick={() => toggle(todo.id)}
            className={`p-3 rounded bg-gray-800 cursor-pointer ${todo.done ? 'opacity-50 line-through' : ''}`}
          >
            {todo.text}
          </li>
        ))}
      </ul>
    </div>
  );
}
